import{_ as e,o as t,c,Q as i}from"./chunks/framework.2275ac6f.js";const h=JSON.parse('{"title":"windows10下vscode配置C++的includePath","description":"","frontmatter":{"title":"windows10下vscode配置C++的includePath","date":"2021-02-24T22:46:38.000Z","tags":["记录问题"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[{"level":3,"title":"解决方案","slug":"解决方案","link":"#解决方案","children":[]}],"relativePath":"src/杂项/windows10下vscode配置C++的includePath.md","lastUpdated":1718000534000}'),o={name:"src/杂项/windows10下vscode配置C++的includePath.md"},a=i('<p>解决：</p><blockquote><p>检测到 #include 错误。请更新 includePath。已为此翻译单元(C:\\miaobuao\\Development\\xxxx.cpp)禁用波形曲线。C/C++(1696)</p></blockquote><p>之前一直使用的linux系统编写c++程序，非常好用，直到最近切换到windows，配置c++运行环境遇到了很多问题。</p><p>为此我安装了MinGW，TDM-GCC，甚至是devC++，但是没用！</p><h3 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-hidden="true">#</a></h3><ol><li>安装TDM-GCC， 我的安装路径是 C:\\TDM-GCC-64</li><li>在vscode中使用 ctrl + shift + P ,找到C/C++：编辑配置(JSON)，然后修改includePath为</li></ol><blockquote><p>C:/TDM-GCC-64/lib/gcc/x86_64-w64-mingw32/9.2.0/include/c++/**</p></blockquote><p>之前就是因为末尾的两个星号没加，所以才报错</p>',8),s=[a];function d(l,n,_,r,p,u){return t(),c("div",null,s)}const w=e(o,[["render",d]]);export{h as __pageData,w as default};
